using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public string DocumentText { get; set; } = string.Empty;

    /// <summary>
    /// Maximum number of sentences in the summary. Defaults to 3.
    /// </summary>
    [Range(1, 20)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public string Summary { get; set; } = string.Empty;
    public int OriginalLength { get; set; }
    public int SummaryLength { get; set; }
}

namespace DocSummary.Services;

/// <summary>
/// Extractive summarization service that scores sentences by word-frequency
/// relevance and returns the top-ranked ones in their original order.
/// </summary>
public class DocumentSummarizationService
{
    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
    {
        "a","an","the","and","or","but","is","are","was","were","be","been",
        "being","have","has","had","do","does","did","will","would","shall",
        "should","may","might","must","can","could","i","you","he","she","it",
        "we","they","me","him","her","us","them","my","your","his","its","our",
        "their","this","that","these","those","in","on","at","to","for","of",
        "with","by","from","as","into","about","between","through","during",
        "before","after","above","below","not","no","nor","so","if","then",
        "than","too","very","just","also","how","what","which","who","whom",
        "when","where","why","all","each","every","both","few","more","most",
        "other","some","such","only","own","same","over","under","again",
        "further","once","here","there","out","up","down"
    };

    public string Summarize(string text, int maxSentences)
    {
        var sentences = SplitSentences(text);

        if (sentences.Count <= maxSentences)
            return string.Join(" ", sentences);

        var wordFrequencies = BuildWordFrequencies(sentences);
        var scored = ScoreSentences(sentences, wordFrequencies);

        // Take the top-scoring sentences but preserve original order.
        var topIndices = scored
            .OrderByDescending(s => s.Score)
            .Take(maxSentences)
            .Select(s => s.Index)
            .Order()
            .ToList();

        return string.Join(" ", topIndices.Select(i => sentences[i]));
    }

    private static List<string> SplitSentences(string text)
    {
        var sentences = new List<string>();
        int start = 0;

        for (int i = 0; i < text.Length; i++)
        {
            if (text[i] is '.' or '!' or '?')
            {
                // Consume trailing punctuation (e.g. "..." or "?!")
                while (i + 1 < text.Length && text[i + 1] is '.' or '!' or '?')
                    i++;

                var sentence = text[start..(i + 1)].Trim();
                if (sentence.Length > 0)
                    sentences.Add(sentence);

                start = i + 1;
            }
        }

        // Remaining text without terminal punctuation.
        var trailing = text[start..].Trim();
        if (trailing.Length > 0)
            sentences.Add(trailing);

        return sentences;
    }

    private static Dictionary<string, int> BuildWordFrequencies(List<string> sentences)
    {
        var freq = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);

        foreach (var sentence in sentences)
        {
            foreach (var word in Tokenize(sentence))
            {
                if (!StopWords.Contains(word))
                    freq[word] = freq.GetValueOrDefault(word) + 1;
            }
        }

        return freq;
    }

    private static List<(int Index, double Score)> ScoreSentences(
        List<string> sentences,
        Dictionary<string, int> wordFrequencies)
    {
        var scored = new List<(int Index, double Score)>();

        for (int i = 0; i < sentences.Count; i++)
        {
            var words = Tokenize(sentences[i]);
            if (words.Count == 0)
            {
                scored.Add((i, 0));
                continue;
            }

            double score = words
                .Where(w => !StopWords.Contains(w))
                .Sum(w => wordFrequencies.GetValueOrDefault(w));

            // Normalize by word count to avoid bias toward long sentences.
            scored.Add((i, score / words.Count));
        }

        return scored;
    }

    private static List<string> Tokenize(string text) =>
        text.Split(' ', StringSplitOptions.RemoveEmptyEntries)
            .Select(w => w.Trim('.', ',', '!', '?', ';', ':', '"', '\'', '(', ')'))
            .Where(w => w.Length > 0)
            .ToList();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController : ControllerBase
{
    private readonly DocumentSummarizationService _service;

    public SummarizeController(DocumentSummarizationService service)
    {
        _service = service;
    }

    /// <summary>
    /// Accepts document text and returns a concise extractive summary.
    /// </summary>
    [HttpPost]
    public IActionResult Summarize([FromBody] SummarizeRequest request)
    {
        var summary = _service.Summarize(request.DocumentText, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalLength = request.DocumentText.Length,
            SummaryLength = summary.Length
        });
    }
}

